    40→function CaseRedirect() {
    41→  const { caseId } = useParams();
    42→  if (!caseId) return <Navigate to="/search" replace />;
    43→  return <Navigate to={`/narrative/${caseId}`} replace />;
    44→}
    45→
    46→function ProtectedRoute({ children }) {
    47→  const { user, isLoading } = useUser();
    48→  if (isLoading) return <PageLoader />;
    49→  if (!user?.isAuthenticated) return <Navigate to="/" replace />;
    50→  return children;
    51→}
    52→
    53→function PageLoader() {
    54→  return (
    55→    <div className="min-h-screen bg-background flex items-center justify-center">
    56→      <PenguinLoading size="sm" />
    57→    </div>
    58→  );
    59→}
    60→
    61→function PageViewTracker() {
    62→  const location = useLocation();
    63→  useEffect(() => {
    64→    trackPageView(location.pathname);
    65→  }, [location.pathname]);
    66→  return null;
    67→}
    68→
    69→function AppRoutes() {
    70→  return (
    71→    <Suspense fallback={<PageLoader />}>
    72→      <Routes>
    73→        <Route path="/" element={<Landing />} />
    74→        <Route path="/landing" element={<Navigate to="/" replace />} />
    75→        <Route path="/onboarding" element={<Navigate to="/" replace />} />
    76→        <Route path="/auth" element={<Auth />} />
    77→        <Route path="/education" element={<ProtectedRoute><Education /></ProtectedRoute>} />
    78→        <Route path="/education/archive" element={<ProtectedRoute><ActivityArchive /></ProtectedRoute>} />
    79→        <Route path="/home" element={<ProtectedRoute><Home /></ProtectedRoute>} />
    80→        <Route path="/search" element={<ProtectedRoute><Search /></ProtectedRoute>} />
    81→        <Route path="/comparison" element={<ProtectedRoute><Comparison /></ProtectedRoute>} />
    82→        <Route path="/story" element={<ProtectedRoute><Story /></ProtectedRoute>} />
    83→        <Route path="/companies" element={<ProtectedRoute><Companies /></ProtectedRoute>} />
    84→        <Route path="/history" element={<ProtectedRoute><History /></ProtectedRoute>} />
    85→        <Route path="/case/:caseId" element={<ProtectedRoute><CaseRedirect /></ProtectedRoute>} />
    86→        <Route path="/narrative/:caseId" element={<ProtectedRoute><Narrative /></ProtectedRoute>} />
    87→        <Route path="/notifications" element={<ProtectedRoute><Notifications /></ProtectedRoute>} />
    88→        <Route path="/portfolio" element={<ProtectedRoute><Portfolio /></ProtectedRoute>} />
    89→        <Route path="/profile" element={<ProtectedRoute><Profile /></ProtectedRoute>} />
    90→        <Route path="/tutor" element={<ProtectedRoute><TutorChat /></ProtectedRoute>} />
    91→        <Route path="/tutor/history" element={<ProtectedRoute><AgentHistoryPage /></ProtectedRoute>} />
    92→        <Route path="/agent" element={<Navigate to="/tutor" replace />} />
    93→        <Route path="/agent/history" element={<Navigate to="/tutor/history" replace />} />
    94→        <Route path="/feedback-survey" element={<ProtectedRoute><FeedbackSurvey /></ProtectedRoute>} />
    95→        <Route path="*" element={<Navigate to="/" replace />} />
    96→      </Routes>
    97→    </Suspense>
    98→  );
    99→}
   100→
   101→export default function App() {
   102→  return (
   103→    <BrowserRouter>
   104→      <ThemeProvider>
   105→        <UserProvider>
   106→          <PortfolioProvider>
   107→          <TutorProvider>
   108→            <TermProvider>
   109→              <ErrorBoundary>
   110→                <ToastProvider>
   111→                  <PageViewTracker />
   112→                  <div className="app-container">
   113→                    <UpdatePrompt />
   114→                    <UpdateNotice />
   115→                    <AppRoutes />
   116→                    <TermBottomSheet />
   117→                    <AgentDock />
