    22→function getVisibleSectionsByMode(mode) {
    23→  if (mode === 'stock') return ['portfolio_summary', 'holdings', 'stock_detail'];
    24→  if (mode === 'education') return ['calendar', 'daily_briefing', 'quiz_mission'];
    25→  if (mode === 'my') return ['profile', 'settings'];
    26→  return ['asset_summary', 'learning_schedule', 'issue_card', 'conversation_cards'];
    27→}
    28→
    29→const SEARCH_TOGGLE_KEY = 'adelie_agent_web_search';
    30→
    31→function readSearchToggle(mode) {
    32→  try {
    33→    const value = localStorage.getItem(SEARCH_TOGGLE_KEY);
    34→    if (value === '1') return true;
    35→    if (value === '0') return false;
    36→    return mode === 'stock';
    37→  } catch {
    38→    return mode === 'stock';
    39→  }
    40→}
